SELECT aer.*,r.development_time,r.maintenance_time,r.manual_test_time,r.scenario_name
FROM auto_execution_record aer LEFT JOIN auto_case_roi r on aer.scenario_id = r.scenario_id
where aer.is_deleted = 0

    and aer.scenario_id = #{req.scenarioId}


    and aer.execution_time > UNIX_TIMESTAMP(#{req.executionStartTime})* 1000


    and aer.execution_time < UNIX_TIMESTAMP(#{req.executionEndTime})* 1000



    and aer.execution_user in

        #{user}



    and aer.execution_status in

        #{status}



    and aer.execution_type in

        #{type}




    and r.development_time < #{req.developmentTime}


    and r.development_time = #{req.developmentTime}


    and r.development_time > #{req.developmentTime}



    and r.maintenance_time < #{req.maintenanceTime}


    and r.maintenance_time = #{req.maintenanceTime}


    and r.maintenance_time > #{req.maintenanceTime}



    and r.manual_test_time < #{req.manualTestTime}


    and r.manual_test_time = #{req.manualTestTime}


    and r.manual_test_time > #{req.manualTestTime}


    ORDER BY execution_time DESC


    ORDER BY execution_time ASC

SELECT e.scenario_id, r.scenario_name, e.execution_status, e.execution_type, e.execution_time, e.execution_user, u.name, r.project_id FROM auto_execution_record e LEFT JOIN auto_case_roi r on e.scenario_id = r.scenario_id INNER JOIN user u on r.author = u.email WHERE e.execution_time > UNIX_TIMESTAMP(#{date}) * 1000 and e.execution_time < UNIX_TIMESTAMP(#{date}) * 1000 + 1000*60*60*8 and e.execution_status != #{executionStatus}
and r.project_id = #{projectId}
and e.execution_type = #{executionType}

SELECT u.name, COUNT(a.scenario_id) AS case_count, a.project_id FROM auto_case_roi a INNER JOIN auto_execution_record e ON a.scenario_id = e.scenario_id INNER JOIN user u on a.author = u.email WHERE e.execution_time > UNIX_TIMESTAMP(#{date}) *1000 AND e.execution_time < UNIX_TIMESTAMP(#{date}) *1000 + 1000*60*60*8
and a.project_id = #{projectId}
and e.execution_status IN
#{item}
and e.execution_type = #{executionType} GROUP BY a.author ORDER BY case_count DESC;
